import java.util.Scanner;

public class SecureBufferExample {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string: ");
        String input = scanner.nextLine();

        // Limit the input length to a safe size
        int maxLength = 10;
        if (input.length() > maxLength) {
            System.out.println("Input exceeds maximum length. Truncating...");
            input = input.substring(0, maxLength);
        }

        char[] buffer = new char[maxLength];

        // Copy the user input into the buffer with bounds checking
        for (int i = 0; i < input.length(); i++) {
            if (i < maxLength) {
                buffer[i] = input.charAt(i);
            } else {
                break; // Stop copying if we reach the end of the buffer
            }
        }

        System.out.println("Buffer content: " + new String(buffer));
    }
}

